mapper.insert:
INSERT INTO nation_war (id, war_date, data, server_id)
VALUES (#{id}, #{warDate}, #{data}, #{serverId})
ON DUPLICATE KEY UPDATE war_date = #{warDate}, data = #{data}

INSERT INTO player_nation (od_user_id, nation, server_id)
VALUES (#{odUserId}, #{nation}, #{serverId})
ON DUPLICATE KEY UPDATE nation = #{nation}, server_id = #{serverId}

INSERT INTO player_merit (od_user_id, merit, server_id)
VALUES (#{odUserId}, #{merit}, #{serverId})
ON DUPLICATE KEY UPDATE merit = #{merit}, server_id = #{serverId}

INSERT INTO nation_war_city_owner (city_id, owner, server_id, update_time)
VALUES (#{cityId}, #{owner}, #{serverId}, #{updateTime})
ON DUPLICATE KEY UPDATE owner = #{owner}, update_time = #{updateTime}
